@Composable private fun Lab(p:Page,e:Element,back:()->Unit,body:@Composable ()->Unit){Column(Modifier.fillMaxSize()){Header(p.title,"${e.name} • INTERACTIVE SCIENCE LAB",back);Glass(Modifier.fillMaxSize().padding(24.dp)){body()}}}
private val nobleCore=mapOf("He" to 2,"Ne" to 10,"Ar" to 18,"Kr" to 36,"Xe" to 54,"Rn" to 86)
private fun shellCounts(z:Int):List<Int>{
 val counts=IntArray(7);val configuration=ELEMENT_PROPERTIES[z-1].configuration
 Regex("\\[([A-Z][a-z]?)\\]").find(configuration)?.groupValues?.get(1)?.let{core->nobleCore[core]?.let{coreZ->shellCounts(coreZ).forEachIndexed{i,v->counts[i]+=v}}}
 Regex("([1-7])[spdf](\\d+)").findAll(configuration.substringAfter(']',configuration)).forEach{m->counts[m.groupValues[1].toInt()-1]+=m.groupValues[2].toInt()}
 return counts.toList().dropLastWhile{it==0}
}
@Composable private fun Atom(n:Int){val t by rememberInfiniteTransition(label="atom").animateFloat(0f,360f,infiniteRepeatable(tween(9000,easing=LinearEasing)),label="orbit");Canvas(Modifier.fillMaxSize().padding(16.dp)){val c=center;val r=min(size.width,size.height)*.10f;if(n>0){drawCircle(Brush.radialGradient(listOf(Color.White,Red,Color.Transparent),c,r*1.7f),r*1.7f,c);repeat(min(n,54)){i->val a=i*2.399963;val d=r*.12f*sqrt(i.toFloat());drawCircle(if(i%2==0)Red else Blue,r*.13f,Offset(c.x+cos(a).toFloat()*d,c.y+sin(a).toFloat()*d))};val counts=shellCounts(n);counts.forEachIndexed{s,count->val rr=r*(1.65f+s*.62f);drawCircle(Cyan.copy(.30f),rr,c,style=Stroke(2f));repeat(count){i->val direction=if(s%2==0)1 else -1;val a=Math.toRadians((direction*t*(1f+s*.04f)+i*360f/count).toDouble());val p=Offset(c.x+cos(a).toFloat()*rr,c.y+sin(a).toFloat()*rr);drawCircle(Cyan.copy(.18f),13f,p);drawCircle(Color.White,7f,p)}}}}}
