@Composable private fun Isotope(e:Element,back:()->Unit){var m by remember{mutableFloatStateOf(e.mass.toFloat())};val neutrons=m.roundToInt()-e.n;Column(Modifier.fillMaxSize()){Header("Isotope Lab","${e.name} • BUILD AND COMPARE ISOTOPES",back);Row(Modifier.fillMaxSize().padding(18.dp),horizontalArrangement=Arrangement.spacedBy(16.dp)){Glass(Modifier.width(210.dp).fillMaxHeight()){Text("ISOTOPE CONTROLS",fontSize=12.sp,color=Cyan);Text("${e.symbol}-${m.roundToInt()}",fontSize=42.sp,color=Gold);Metric("Protons","${e.n}",Red);Metric("Neutrons","$neutrons",Blue);Metric("Mass number","${m.roundToInt()}");Text("Adjust mass number",fontSize=10.sp);Slider(value=m,onValueChange={m=it.roundToInt().toFloat()},valueRange=max(e.n,e.mass-8).toFloat()..(e.mass+8).toFloat(),steps=15)};Glass(Modifier.weight(1f).fillMaxHeight()){Box(Modifier.weight(1f).fillMaxWidth()){Atom(e.n);Text("NUCLEUS: ${e.n}p + ${neutrons}n",Modifier.align(Alignment.TopCenter),color=Cyan,fontSize=11.sp)};Text("Isotopes have the same proton count but different neutron counts.",fontSize=11.sp,color=Color.White.copy(.75f))};Glass(Modifier.width(220.dp).fillMaxHeight()){Text("ISOTOPE INFORMATION",fontSize=12.sp,color=Cyan);Metric("Nuclide","${e.symbol}-${m.roundToInt()}");Metric("Atomic number","${e.n}");Metric("Mass number","${m.roundToInt()}");Metric("Neutron count","$neutrons");Text("Stability varies by nuclide. This builder does not label an isotope stable without evaluated nuclear data.",fontSize=10.sp,lineHeight=15.sp,color=Gold)}}}}
@Composable private fun Ion(e:Element,back:()->Unit){var q by remember{mutableFloatStateOf(0f)};val maximumPositive=min(3,e.n);val charge=q.roundToInt().coerceIn(-3,maximumPositive);val electrons=e.n-charge;Column(Modifier.fillMaxSize()){Header("${e.name} (${e.symbol})","ION BUILDER • ADD OR REMOVE ELECTRONS",back);Row(Modifier.fillMaxSize().padding(18.dp),horizontalArrangement=Arrangement.spacedBy(16.dp)){Glass(Modifier.width(210.dp).fillMaxHeight()){Text("ION CONTROLS",fontSize=12.sp,color=Cyan);Text(if(charge==0)e.symbol else "${e.symbol}${if(charge>0)"${charge}+" else "${-charge}−"}",fontSize=48.sp,color=Cyan);Metric("Charge","$charge",Gold);Metric("Protons","${e.n}",Red);Metric("Electrons","$electrons",Cyan);Text("Electron change",fontSize=10.sp);Slider(value=charge.toFloat(),onValueChange={q=it.roundToInt().coerceIn(-3,maximumPositive).toFloat()},valueRange=-3f..maximumPositive.toFloat(),steps=(maximumPositive+2).coerceAtLeast(0))};Glass(Modifier.weight(1f).fillMaxHeight()){Atom(electrons);Text(if(charge>0)"${e.symbol} → ${e.symbol}${charge}+ + ${charge}e⁻" else if(charge<0)"${e.symbol} + ${-charge}e⁻ → ${e.symbol}${-charge}−" else "Neutral atom: protons = electrons",fontSize=13.sp,color=Gold)};Glass(Modifier.width(210.dp).fillMaxHeight()){Text("CHARGE ACCOUNTING",fontSize=12.sp,color=Cyan);Metric("Nuclear charge","+${e.n}");Metric("Electron charge","−$electrons");Metric("Net charge","$charge",Gold);Text("Changing ion charge changes electrons only. The nucleus and element identity remain unchanged.",fontSize=10.sp,lineHeight=16.sp)}}}}
@Composable private fun Molecule(){Canvas(Modifier.fillMaxSize()){val c=center;val l=Offset(c.x-size.width*.17f,c.y+size.height*.18f);val r=Offset(c.x+size.width*.17f,c.y+size.height*.18f);drawLine(Color.LightGray,c,l,18f);drawLine(Color.LightGray,c,r,18f);drawCircle(Brush.radialGradient(listOf(Color.White,Red,Color(0xFF7C102B)),c,size.minDimension*.12f),size.minDimension*.11f,c);drawCircle(Brush.radialGradient(listOf(Color.White,Color(0xFF9EB4C8)),l,size.minDimension*.07f),size.minDimension*.067f,l);drawCircle(Brush.radialGradient(listOf(Color.White,Color(0xFF9EB4C8)),r,size.minDimension*.07f),size.minDimension*.067f,r);drawArc(Gold,-58f,116f,false,topLeft=Offset(c.x-size.width*.11f,c.y),size=androidx.compose.ui.geometry.Size(size.width*.22f,size.height*.27f),style=Stroke(3f))}}
