@Composable private fun Particles(phase:String){val t by rememberInfiniteTransition(label="matter").animateFloat(0f,1f,infiniteRepeatable(tween(if(phase=="GAS")650 else 1600,easing=LinearEasing),RepeatMode.Restart),label="motion");Canvas(Modifier.fillMaxWidth().weight(1f)){drawRoundRect(Color(0x6625A8D0),style=Stroke(3f),cornerRadius=androidx.compose.ui.geometry.CornerRadius(18f));repeat(30){i->val base=when(phase){"SOLID"->Offset(size.width*(.16f+(i%6)*.135f),size.height*(.18f+(i/6)*.15f));"LIQUID"->Offset(size.width*(.10f+((i*37)%83)/100f),size.height*(.42f+((i*53)%48)/100f));else->Offset(size.width*(.06f+((i*37)%89)/100f),size.height*(.08f+((i*61)%84)/100f))};val motion=when(phase){"SOLID"->3f;"LIQUID"->10f;else->24f};val p=Offset(base.x+sin(i*1.7f+t*6.28f)*motion,base.y+cos(i*2.1f+t*5.4f)*motion);val angle=i*.7f;val h1=Offset(p.x+cos(angle)*9f,p.y+sin(angle)*9f);val h2=Offset(p.x+cos(angle+1.83f)*9f,p.y+sin(angle+1.83f)*9f);drawLine(Color.White.copy(.65f),p,h1,3f);drawLine(Color.White.copy(.65f),p,h2,3f);drawCircle(Red,6f,p);drawCircle(Color(0xFFE7F5FF),3.8f,h1);drawCircle(Color(0xFFE7F5FF),3.8f,h2)}}}
